// ── CommonJS exports ──
module.exports.PLATFORM_GENERATION_SPECS = PLATFORM_GENERATION_SPECS;
module.exports.AUTONOMY_MODES = AUTONOMY_MODES;
module.exports.WF1_GUARDRAILS = WF1_GUARDRAILS;
module.exports.buildStrategicDecisionPrompt = buildStrategicDecisionPrompt;
module.exports.buildPlatformGenerationPrompt = buildPlatformGenerationPrompt;
